import{_ as o,c as t,o as s,ag as e}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Избранное","description":"","frontmatter":{"title":"Избранное"},"headers":[],"relativePath":"ru/store/favorite.md","filePath":"ru/store/favorite.md"}'),a={name:"ru/store/favorite.md"};function n(i,r,l,g,h,p){return s(),t("div",null,[...r[0]||(r[0]=[e('<h1 id="избранное-pinia-store" tabindex="-1">Избранное (Pinia Store) <a class="header-anchor" href="#избранное-pinia-store" aria-label="Permalink to &quot;Избранное (Pinia Store)&quot;">​</a></h1><p><strong>Избранные сторы</strong> — это сохраняемый список <strong>Pinia store</strong>, который помогает быстрее ориентироваться во вкладке <strong>Stores</strong>: отмеченные строки поднимаются <strong>в начало списка</strong>, рядом отображается <strong>звезда</strong>, а в шапке доступен счётчик найденных избранных среди текущих результатов.</p><p>Общее описание вкладки Store: <a href="/docs/ru/store/general.html">Основные возможности</a>. Избранное <strong>компонентов Vue</strong> (вкладка Props) — отдельный механизм: <a href="/docs/ru/props/favorite.html">Избранное (Props)</a>.</p><hr><h2 id="где-добавить-и-убрать" tabindex="-1">Где добавить и убрать <a class="header-anchor" href="#где-добавить-и-убрать" aria-label="Permalink to &quot;Где добавить и убрать&quot;">​</a></h2><p>Добавить store в избранное можно несколькими способами.</p><ul><li><strong>В карточке store</strong> — в заголовке доступна кнопка <strong>звезды</strong>, которая включает или снимает признак избранного для текущего store.</li><li><strong>Через контекстное меню строки в таблице Stores</strong> — команда добавления или удаления доступна среди действий над выбранной строкой.</li><li><strong>В таблице Stores</strong> — быстрый клик по области <strong>звезды</strong> у строки также переключает избранное, даже если иконка ещё не отображается постоянно.</li><li><strong>В Options</strong> — секция <strong>Favorite Stores</strong> в блоке настроек <strong>Pinia</strong> позволяет просматривать записи, вводить имя вручную, удалять элементы и открывать выбранную запись для редактирования.</li></ul><p>Настройки сохраняются в общем хранилище инспектора вместе с остальными параметрами.</p><hr><h2 id="точное-имя-и-маски" tabindex="-1">Точное имя и маски <a class="header-anchor" href="#точное-имя-и-маски" aria-label="Permalink to &quot;Точное имя и маски&quot;">​</a></h2><p>Каждая запись в списке избранного задаёт <strong>шаблон имени store</strong>.</p><ul><li>Если запись <strong>не содержит</strong> символ <strong><code>*</code></strong>, используется <strong>точное совпадение</strong>: звезда отображается только у store с таким же именем.</li><li>Символ <strong><code>*</code></strong> работает как <strong>маска произвольного фрагмента имени</strong>. Например, шаблон <strong>use*Store</strong> может совпасть с <strong>useUserStore</strong>, <strong>useAuthStore</strong> и другими именами, подходящими под выражение.</li></ul><p>При снятии избранного со строки таблицы удаляются все записи, которые считаются совпадающими для этого store: как точные, так и подходящие по маске.</p><p>В форме ручного ввода в <strong>Options</strong> поддержка wildcard сохраняется в том же формате.</p><hr><h2 id="что-именно-сохраняется" tabindex="-1">Что именно сохраняется <a class="header-anchor" href="#что-именно-сохраняется" aria-label="Permalink to &quot;Что именно сохраняется&quot;">​</a></h2><p>Для каждой записи инспектор хранит:</p><ul><li><strong>отображаемое имя store</strong>;</li><li><strong>шаблон совпадения</strong> (если используется маска);</li><li>при наличии — <strong>внутренний идентификатор текущей сессии</strong>, связанный с найденным экземпляром;</li><li><strong>время добавления</strong> для отображения в настройках.</li></ul><p>Это позволяет повторно применять список после обновления дерева store.</p><hr><h2 id="как-выполняется-сопоставление" tabindex="-1">Как выполняется сопоставление <a class="header-anchor" href="#как-выполняется-сопоставление" aria-label="Permalink to &quot;Как выполняется сопоставление&quot;">​</a></h2><p>При загрузке списка store инспектор последовательно сравнивает имена текущих записей с сохранёнными шаблонами.</p><ul><li>Сначала проверяется <strong>точное совпадение имени</strong>.</li><li>Затем — совпадение по <strong>маске</strong>, если запись содержит символ <strong><code>*</code></strong>.</li><li>Если доступны дополнительные данные текущей сессии, они используются для уточнения связи с уже найденной строкой.</li></ul><p>Если несколько store подходят под одну маску, звезда отображается у всех совпавших строк.</p><hr><h2 id="сортировка-и-счетчик" tabindex="-1">Сортировка и счётчик <a class="header-anchor" href="#сортировка-и-счетчик" aria-label="Permalink to &quot;Сортировка и счётчик&quot;">​</a></h2><p>После обновления списка таблица <strong>Stores</strong> размещает избранные строки <strong>выше остальных</strong>.</p><p>Рядом с полем поиска отображается бейдж вида <strong>«найдено / всего»</strong>: сколько избранных store сейчас видно с учётом поиска и сколько записей сохранено в списке избранного.</p><p>Клик по бейджу может использоваться как быстрый переход в <strong>Options</strong> к секции избранных store.</p><hr><h2 id="редактирование-в-options" tabindex="-1">Редактирование в Options <a class="header-anchor" href="#редактирование-в-options" aria-label="Permalink to &quot;Редактирование в Options&quot;">​</a></h2><p>Выбранную запись можно открыть в панели деталей и изменить имя шаблона.</p><p>После сохранения обновляется связанное имя записи; если используется маска, новое значение сразу участвует в последующем сопоставлении.</p><p>Пустое имя лучше не оставлять: такая запись не даст полезного совпадения.</p><hr><h2 id="практические-советы" tabindex="-1">Практические советы <a class="header-anchor" href="#практические-советы" aria-label="Permalink to &quot;Практические советы&quot;">​</a></h2><ul><li>Удобно добавлять в избранное <strong>основные store проекта</strong>: пользователь, настройки, состояние интерфейса.</li><li><strong>Маски</strong> полезны в проектах с однотипным именованием, но слишком широкий шаблон может выделить лишние строки.</li><li>Избранное <strong>не влияет</strong> на выполнение Pinia в приложении и хранится локально в настройках инспектора.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/store/general.html">Основные возможности Store</a></li><li><a href="/docs/ru/props/favorite.html">Избранное (Props)</a></li><li><a href="/docs/ru/options/customize.html">Персонализация / настройки</a></li></ul>',40)])])}const c=o(a,[["render",n]]);export{u as __pageData,c as default};
